// src/pages/Home.js
import React, { useState, useEffect } from "react";
import { Link } from "react-router-dom";
import { motion, AnimatePresence } from "framer-motion";
import {
  Palette,
  Building,
  ShoppingBag,
  Megaphone,
  Star,
  TrendingUp,
  Crown,
} from "lucide-react";
import Footer from "../components/Footer";
import {
  auth,
  loginWithEmail,
  signUpWithEmail,
  signInWithGoogle,
  logout,
  monitorAuthState,
} from "../firebase";

function Home() {
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [isLogin, setIsLogin] = useState(true);
  const [user, setUser] = useState(null);
  const [formData, setFormData] = useState({ email: "", password: "", name: "" });

  useEffect(() => {
    const unsubscribe = monitorAuthState(setUser);
    return () => unsubscribe();
  }, []);

  const handleChange = (e) =>
    setFormData({ ...formData, [e.target.name]: e.target.value });

  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      if (isLogin) {
        await loginWithEmail(formData.email, formData.password);
      } else {
        await signUpWithEmail(formData.email, formData.password, formData.name);
      }
      setIsModalOpen(false);
    } catch (error) {
      alert(error.message);
    }
  };

  const handleGoogleLogin = async () => {
    try {
      await signInWithGoogle();
      setIsModalOpen(false);
    } catch (error) {
      alert(error.message);
    }
  };

  return (
    <div className="min-h-screen flex flex-col bg-primary text-light font-sans">
      <main className="flex-grow">
        {/* Hero Section */}
        <section className="relative min-h-screen flex flex-col justify-center items-center text-center bg-gradient-to-br from-primary via-secondary to-black text-light overflow-hidden px-6 md:px-20">
          <motion.h1
            className="text-4xl md:text-5xl lg:text-6xl font-bold mb-6"
            initial={{ opacity: 0, y: 50 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ duration: 0.8 }}
          >
            The Grand Coordinating Enterprise
          </motion.h1>
          <motion.p
            className="text-lg md:text-xl mb-8 max-w-2xl text-gray-300"
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            transition={{ delay: 0.3 }}
          >
            Where creativity meets commerce, and vision shapes reality.
          </motion.p>

          {user ? (
            <div className="flex flex-col md:flex-row justify-center gap-4">
              <Link to="/hub">
                <motion.button
                  className="px-6 py-3 bg-accent text-white font-semibold rounded-lg shadow hover:bg-blue-600 transition"
                  whileHover={{ scale: 1.05 }}
                  whileTap={{ scale: 0.95 }}
                >
                  Enter Community Hub
                </motion.button>
              </Link>
              <button
                onClick={logout}
                className="px-6 py-3 bg-transparent border border-accent text-accent font-semibold rounded-lg hover:bg-accent hover:text-black transition"
              >
                Logout
              </button>
            </div>
          ) : (
            <div className="flex flex-col md:flex-row justify-center gap-4">
              <Link to="/about">
                <motion.button
                  className="px-6 py-3 bg-accent text-white font-semibold rounded-lg shadow hover:bg-blue-600 transition"
                  whileHover={{ scale: 1.05 }}
                  whileTap={{ scale: 0.95 }}
                >
                  Explore Our Empire
                </motion.button>
              </Link>
              <button
                onClick={() => setIsModalOpen(true)}
                className="px-6 py-3 bg-transparent border border-accent text-accent font-semibold rounded-lg hover:bg-accent hover:text-black transition"
              >
                Sign Up / Login
              </button>
            </div>
          )}
        </section>

        {/* About Section */}
        <section className="py-16 text-center px-6 md:px-20 bg-secondary">
          <h2 className="text-3xl font-bold mb-6 text-accent">About Us</h2>
          <p className="max-w-3xl mx-auto text-md md:text-lg text-gray-300">
            We are a multidimensional powerhouse uniting design, fashion,
            architecture, real estate, trade, and marketing — one coordinated
            empire of innovation and legacy.
          </p>
        </section>

        {/* Core Domains */}
        <section className="py-20 px-6 md:px-20 bg-primary text-light">
          <h2 className="text-3xl font-bold text-center mb-12 text-accent">
            Our Core Domains
          </h2>
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-8">
            {[
              { Icon: Palette, title: "Design & Fashion", text: "Visuals and garments that express culture." },
              { Icon: Building, title: "Architecture & Real Estate", text: "Spaces that inspire and endure." },
              { Icon: ShoppingBag, title: "Trade & Commerce", text: "Connecting global opportunities." },
              { Icon: Megaphone, title: "Marketing & Commercials", text: "Turning ideas into impact." },
            ].map(({ Icon, title, text }, i) => (
              <article
                key={i}
                className="p-6 bg-secondary rounded-xl shadow-card text-center motion-safe:hover:-translate-y-2 transition-transform"
              >
                <Icon size={40} className="mx-auto text-accent mb-4" />
                <h3 className="font-bold text-lg mb-2">{title}</h3>
                <p className="text-gray-300">{text}</p>
              </article>
            ))}
          </div>
        </section>

        {/* Purpose & Vision */}
        <section className="py-20 px-6 md:px-20 flex flex-col md:flex-row items-center gap-12 bg-secondary">
          <motion.div
            className="w-full md:w-1/2"
            initial={{ opacity: 0, y: 30 }}
            whileInView={{ opacity: 1, y: 0 }}
            viewport={{ once: true }}
            transition={{ duration: 0.8 }}
          >
            <h2 className="text-3xl font-bold mb-6 text-accent">Purpose & Vision</h2>
            <p className="text-md text-gray-300 mb-4">
              <strong>Purpose:</strong> To coordinate greatness across industries.
            </p>
            <p className="text-md text-gray-300">
              <strong>Vision:</strong> To stand as the epicenter of creativity,
              innovation, and timeless excellence.
            </p>
          </motion.div>

          <motion.div
            className="w-full md:w-1/2 h-64 bg-gradient-to-r from-accent to-yellow-500 rounded-xl shadow-lg mt-6 md:mt-0"
            initial={{ opacity: 0, y: 50 }}
            whileInView={{ opacity: 1, y: 0 }}
            viewport={{ once: true }}
            transition={{ duration: 0.8, type: 'spring', stiffness: 120, damping: 15 }}
          />
        </section>

        {/* Final CTA */}
        <section className="py-20 px-6 md:px-20 text-center bg-primary">
          <h2 className="text-3xl font-bold mb-6 text-accent">Join the Empire</h2>
          <p className="max-w-2xl mx-auto text-gray-300 mb-8">
            Godemar’s Empire is where design meets destiny — a hub for creativity,
            collaboration, and commerce.
          </p>
          <div className="flex flex-col md:flex-row justify-center gap-4">
            <Link to="/contact">
              <button className="px-6 py-3 bg-accent text-white font-semibold rounded-lg shadow hover:bg-blue-600 transition">
                Work With Us
              </button>
            </Link>
            {!user && (
              <button
                onClick={() => setIsModalOpen(true)}
                className="px-6 py-3 border border-accent text-accent font-semibold rounded-lg hover:bg-accent hover:text-black transition"
              >
                Signup / Login
              </button>
            )}
          </div>
        </section>
      </main>

      <Footer />

      {/* Signup/Login Modal */}
      <AnimatePresence>
        {isModalOpen && (
          <motion.div
            className="fixed inset-0 bg-black bg-opacity-60 flex justify-center items-center z-50"
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            exit={{ opacity: 0 }}
          >
            <motion.div
              className="bg-secondary rounded-xl w-full max-w-md p-6 relative text-light"
              initial={{ scale: 0.8, opacity: 0 }}
              animate={{ scale: 1, opacity: 1 }}
              exit={{ scale: 0.8, opacity: 0 }}
              transition={{ duration: 0.3 }}
            >
              <button
                className="absolute top-3 right-3 text-gray-400 hover:text-accent"
                onClick={() => setIsModalOpen(false)}
              >
                ✕
              </button>

              <div className="flex justify-center mb-4">
                <button
                  className={`px-4 py-2 font-semibold rounded-t-lg ${
                    isLogin ? "bg-accent text-black" : "bg-primary text-gray-400"
                  }`}
                  onClick={() => setIsLogin(true)}
                >
                  Login
                </button>
                <button
                  className={`px-4 py-2 font-semibold rounded-t-lg ${
                    !isLogin ? "bg-accent text-black" : "bg-primary text-gray-400"
                  }`}
                  onClick={() => setIsLogin(false)}
                >
                  Signup
                </button>
              </div>

              <form onSubmit={handleSubmit} className="flex flex-col gap-4 mt-4">
                {!isLogin && (
                  <input
                    type="text"
                    name="name"
                    placeholder="Full Name"
                    value={formData.name}
                    onChange={handleChange}
                    className="px-4 py-2 rounded-lg border border-gray-700 bg-primary text-light focus:ring-2 focus:ring-accent"
                  />
                )}
                <input
                  type="email"
                  name="email"
                  placeholder="Email Address"
                  value={formData.email}
                  onChange={handleChange}
                  className="px-4 py-2 rounded-lg border border-gray-700 bg-primary text-light focus:ring-2 focus:ring-accent"
                />
                <input
                  type="password"
                  name="password"
                  placeholder="Password"
                  value={formData.password}
                  onChange={handleChange}
                  className="px-4 py-2 rounded-lg border border-gray-700 bg-primary text-light focus:ring-2 focus:ring-accent"
                />
                <button
                  type="submit"
                  className="px-4 py-2 bg-accent text-black font-semibold rounded-lg hover:bg-yellow-400 transition"
                >
                  {isLogin ? "Login" : "Signup"}
                </button>
              </form>

              <div className="flex items-center my-4">
                <hr className="flex-grow border-gray-700" />
                <span className="px-2 text-gray-400 text-sm">OR</span>
                <hr className="flex-grow border-gray-700" />
              </div>

              <button
                onClick={handleGoogleLogin}
                className="w-full flex items-center justify-center gap-2 px-4 py-2 border border-gray-700 rounded-lg hover:bg-primary transition font-semibold text-light"
              >
                <img
                  src="https://upload.wikimedia.org/wikipedia/commons/5/53/Google_%22G%22_Logo.svg"
                  alt="Google"
                  className="w-5 h-5"
                />
                {isLogin ? "Login with Google" : "Signup with Google"}
              </button>

              <p className="text-sm text-gray-400 mt-4 text-center">
                By continuing, you agree to our terms and privacy policy.
              </p>
            </motion.div>
          </motion.div>
        )}
      </AnimatePresence>
    </div>
  );
}

export default Home;
